=@('/health','/openapi.json','/map/listings','/map/sales-layers/verified-history','/map/sales-history/status','/map/sales-history/external-evidence','/map/sales-history/parcels','/map/sales-history/combined'); Write-Output 'TASK: TerraYield status check'; Write-Output 'PROGRESS: 100%'; docker compose -f docker-compose.yml -f docker-compose.aays-fast-start.yml ps; docker inspect terrayield_land_api --format '{{json .Config.Cmd}}'; foreach ($ep in $endpoints) { try { $sw=[System.Diagnostics.Stopwatch]::StartNew(); $r=Invoke-WebRequest -Uri ('http://localhost:8010'+$ep) -UseBasicParsing -TimeoutSec 45; $sw.Stop(); Write-Output ('OK ' + $ep + ' status=' + $r.StatusCode + ' ms=' + $sw.ElapsedMilliseconds + ' bytes=' + $r.Content.Length) } catch { Write-Output ('FAIL ' + $ep + ' error=' + $_.Exception.Message) } }
